#include <iostream>
#include <vector>
using namespace std;

bool isPrime(int n) {
    if (n < 2) return false;
    for (int i = 2; i * i <= n; ++i)
        if (n % i == 0) return false;
    return true;
}

void generatePattern(int n) {
    vector<int> seq;
    int a = 1, b = 1;
    for (int i = 0; i < n; ++i) {
        int next = a + b;
        if (isPrime(next)) seq.push_back(next * 2);
        else seq.push_back(next);
        a = b;
        b = next;
    }
    for (int val : seq) cout << val << " ";
}

int main() {
    generatePattern(20);
    return 0;
}
